// Template code for printing output to console
#include <iostream>

// Define class Solution with solve method
class Solution {
public:
    bool solve(vector<int>& nums, int start, int end) {
        if (start == end) return true;
        vector<int> prefix_sum(end - start + 1);
        for (int i = start; i < end; i++) {
            prefix_sum[i - start] = nums[i];
        }
        for (int i = 1; i < end - start + 1; i++) {
            if (prefix_sum[i] < prefix_sum[i - 1]) return false;
        }
        if (start + ceil((end - start + 1) / 2.0) != end) return true;
        return false;
    }
};

